// shadcn
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger
} from "@/components/ui/accordion";

// constants
const faqs = [
  {
    question: "Why Must I Make Payment Immediately At Checkout?",
    answer:
      "As an added value, every time you rate the products you earn points which go straight to your account. Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  },
  {
    question: "Why Must I Make Payment Immediately At Checkout?",
    answer:
      "As an added value, every time you rate the products you earn points which go straight to your account. Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  },
  {
    question: "How Can I Track My Orders & Payment?",
    answer:
      "As an added value, every time you rate the products you earn points which go straight to your account. Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  }
];

//  ------------------------------ | FAQ - 10 | ------------------------------  //

export default function Faq10() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header */}
        <div className="mx-auto mb-16 max-w-lg text-center">
          <p className="mb-4 text-lg font-medium uppercase tracking-widest text-yellow-500">
            F.A.Q
          </p>
          <h2 className="mb-6">Popular FAQ's</h2>
          <p className="text-muted-foreground text-lg">
            This is a big one and i consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* FAQ Accordion */}
        <div className="grid grid-cols-12">
          <div className="col-span-12 md:col-start-3 md:col-span-8 lg:col-start-4 lg:col-span-6">
            <Accordion className="space-y-2" defaultValue={["item-0"]}>
              {faqs.map((item, index) => (
                <AccordionItem
                  key={index}
                  value={`item-${index}`}
                  className="border-none"
                >
                  <AccordionTrigger>
                    <span className="text-left font-semibold text-lg">
                      {item.question}
                    </span>
                  </AccordionTrigger>
                  <div className="h-0.5 w-full bg-primary" />
                  <AccordionContent className="text-muted-foreground leading-relaxed">
                    <div className="py-6">{item.answer}</div>
                  </AccordionContent>
                </AccordionItem>
              ))}
            </Accordion>
          </div>
        </div>
      </div>
    </section>
  );
}
